import type { ReactNode } from 'react';
import type {
  PolymorphicComponentRestricted,
  PolymorphicComponent,
} from '@andes/common';

export type VisuallyHiddenComponentTypes =
  | 'div'
  | 'h1'
  | 'h2'
  | 'h3'
  | 'h4'
  | 'h5'
  | 'h6'
  | 'p'
  | 'span';

export interface VisuallyHiddenProps {
  children?: ReactNode;
}

export interface VisuallyHiddenFocusableProps extends VisuallyHiddenProps {
  className?: string;
}

/**
 * Used to hide content visually but keep it accessible to screen readers.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/visually-hidden#props | Documentation}
 * @example
 * import { VisuallyHidden } from '@andes/visually-hidden';
 *
 * const MyComponent = () => (
    <VisuallyHidden>
      <input type="text" />
    </VisuallyHidden>
 * );
 */
export const VisuallyHidden: PolymorphicComponentRestricted<
  'span',
  VisuallyHiddenProps,
  VisuallyHiddenComponentTypes
>;

/**
 * Used to hide content visually but keep it accessible to screen readers, can be accessed by keyboard.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/visually-hidden#props | Documentation}
 * @example
 * import { VisuallyHiddenFocusable } from '@andes/visually-hidden';
 *
 * const MyComponent = () => (
    <VisuallyHiddenFocusable>
      <input type="text" />
    </VisuallyHiddenFocusable>
 * );
 */
export const VisuallyHiddenFocusable: PolymorphicComponent<
  'button',
  VisuallyHiddenFocusableProps
>;
